- This question assumes that the term of a loan facility refers to its duration in time (e.g., months, years), but the exact unit of time is not explicitly stated in the query; 
- Understanding the concept of average and its implications in financial analysis; 
- Familiarity with the context of loan facilities and their terms.

sql:
SELECT nCino_name, description
FROM data_tables
WHERE display_order = ROUND(display_order) AND description LIKE '%aggregated%';

SELECT COUNT(*) 
FROM facilities 
WHERE loan_amount > (SELECT AVG(loan_amount) FROM facilities);

SELECT facility_id, COUNT(*) AS facility_count
FROM facilities
GROUP BY facility_id;

SELECT description
FROM data_tables
WHERE nCino_name = 'LLC_BI__Legal_Entities__c';

SELECT COUNT(facility_id)
FROM facilities
WHERE interest_rate > (SELECT AVG(interest_rate) FROM loans);

SELECT COUNT(DISTINCT entity_id) 
FROM entity_involvements
WHERE loan_id = 0;

SELECT nCino_name, description, display_order
FROM data_tables
WHERE table_id IN (0, 1);

SELECT nCino_name
FROM data_tables
WHERE nCino_label = 'Facility' AND display_order IS NOT NULL;
